PRAGMA foreign_keys = ON;
CREATE TABLE IF NOT EXISTS users (user_id TEXT PRIMARY KEY,email TEXT UNIQUE,full_name TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tenants (tenant_id TEXT PRIMARY KEY,slug TEXT UNIQUE NOT NULL,business_name TEXT NOT NULL,business_type TEXT NOT NULL DEFAULT 'store',plan TEXT DEFAULT 'starter',status TEXT DEFAULT 'active',owner_name TEXT,phone TEXT,whatsapp_number TEXT,logo_url TEXT,hero_url TEXT,theme_json TEXT,payment_mode TEXT DEFAULT 'sale_unified',created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tenant_users (tenant_id TEXT NOT NULL,user_id TEXT NOT NULL,role TEXT NOT NULL DEFAULT 'owner',created_at TEXT DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(tenant_id,user_id),FOREIGN KEY(tenant_id) REFERENCES tenants(tenant_id),FOREIGN KEY(user_id) REFERENCES users(user_id));
CREATE TABLE IF NOT EXISTS items (item_id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,item_type TEXT NOT NULL DEFAULT 'product',name TEXT NOT NULL,description TEXT,price REAL DEFAULT 0,currency TEXT DEFAULT 'USD',category TEXT,image_url TEXT,active INTEGER DEFAULT 1,sort_order INTEGER DEFAULT 0,metadata_json TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,updated_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(tenant_id) REFERENCES tenants(tenant_id));
CREATE TABLE IF NOT EXISTS customers (customer_id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,name TEXT,phone TEXT,email TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(tenant_id) REFERENCES tenants(tenant_id));
CREATE TABLE IF NOT EXISTS orders (order_id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,customer_id TEXT,item_summary TEXT,total_amount REAL,currency TEXT DEFAULT 'USD',payment_status TEXT DEFAULT 'pending',fulfilment_status TEXT DEFAULT 'created',payment_reference TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(tenant_id) REFERENCES tenants(tenant_id));
CREATE TABLE IF NOT EXISTS bookings (booking_id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,customer_id TEXT,item_id TEXT,booking_date TEXT,booking_time TEXT,deposit_amount REAL DEFAULT 0,total_amount REAL DEFAULT 0,payment_status TEXT DEFAULT 'pending',booking_status TEXT DEFAULT 'created',notes TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(tenant_id) REFERENCES tenants(tenant_id));
CREATE TABLE IF NOT EXISTS reviews (review_id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,customer_id TEXT,rating INTEGER,comment TEXT,reply TEXT,public INTEGER DEFAULT 0,status TEXT DEFAULT 'new',created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(tenant_id) REFERENCES tenants(tenant_id));
CREATE TABLE IF NOT EXISTS payouts (payout_id TEXT PRIMARY KEY,tenant_id TEXT NOT NULL,gross_amount REAL,fee_amount REAL,net_amount REAL,status TEXT DEFAULT 'pending',scheduled_for TEXT,paid_at TEXT,reference TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(tenant_id) REFERENCES tenants(tenant_id));
CREATE TABLE IF NOT EXISTS notifications (notification_id TEXT PRIMARY KEY,tenant_id TEXT,customer_id TEXT,channel TEXT,type TEXT,status TEXT DEFAULT 'scheduled',payload_json TEXT,scheduled_for TEXT,sent_at TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS audit_logs (log_id TEXT PRIMARY KEY,tenant_id TEXT,user_id TEXT,action TEXT,entity_type TEXT,entity_id TEXT,ip_address TEXT,metadata_json TEXT,created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS idx_items_tenant ON items(tenant_id);
CREATE INDEX IF NOT EXISTS idx_orders_tenant ON orders(tenant_id);
CREATE INDEX IF NOT EXISTS idx_bookings_tenant ON bookings(tenant_id);
